INSERT INTO failure_diagnoses (id, cluster_id, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (1, 1, 'completed', 'demo', 'demo', 'infrastructure', 'high', 'Checkout button click times out consistently — suspected slow CI agent or network latency spike causing locator resolution delay.', 'The locator.click timeout (30 000 ms) is exceeded when the checkout page renders slowly on the CI runner. The root cause is a missing explicit wait for the payment form to become interactive before clicking, combined with CI infrastructure variability.', '{"evidence":["TimeoutError occurs at tests/checkout/checkout.spec.ts:42 in both affected tests","Error fires during locator.click — the element is present in DOM but not yet interactive","Failure rate correlates with high-load CI runs (build numbers 1180-1200)"],"suggestedFix":{"description":"Add an explicit waitForLoadState(\"networkidle\") or waitFor condition before the click, and increase the locator timeout for the payment button to 60 000 ms.","file":"tests/checkout/checkout.spec.ts","code":"await page.waitForLoadState(\"networkidle\");\nawait page.getByRole(\"button\", { name: \"Pay\" }).click({ timeout: 60000 });"},"preventionTips":["Use page.waitForLoadState() before interacting with dynamically loaded payment forms","Add a CI-aware timeout multiplier for payment-related actions","Consider adding a Playwright expect.poll for the button to have aria-disabled=false"]}', NULL, 1240, 380, 2850, 1745566200, 1745566200);
INSERT INTO failure_diagnoses (id, cluster_id, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (2, 3, 'completed', 'demo', 'demo', 'app-bug', 'high', 'POST /auth/login and related auth tests fail with HTTP 500 — server-side exception in the authentication handler.', 'The authentication endpoint returns HTTP 500 instead of the expected 200, causing the assertion expect(received).toBe(200).toBe(500) to fail. This indicates a regression in the auth service — likely an unhandled exception in the login handler introduced in recent commits.', '{"evidence":["Expected: 200 / Received: 500 in two separate auth test cases","Both failures share the same cluster fingerprint, confirming a single root cause","The error started appearing in builds after the auth refactor commits"],"suggestedFix":{"description":"Inspect the /auth/login endpoint for unhandled exceptions. Add error handling around the credential verification logic and ensure the response status code is correctly set for each code path.","file":"tests/api/auth.spec.ts","code":null},"preventionTips":["Add integration tests that exercise the auth endpoint with a real DB connection","Set up error monitoring (Sentry, Datadog) on the /auth/login endpoint to catch 5xx regressions early","Add a smoke test in CI that hits /auth/login before the full test suite"]}', NULL, 980, 310, 2100, 1745566200, 1745566200);
